def min_removals_to_make_valid(s: str) -> int:
    open_count = 0
    removals = 0

    for char in s:
        if char == '(':
            open_count += 1
        elif char == ')':
            if open_count > 0:
                open_count -= 1
            else:
                # Unmatched closing parenthesis
                removals += 1

    # Any remaining open_count means unmatched opening parentheses
    removals += open_count

    return removals
